use App\Core\Csrf;
use App\Core\Router;
use App\Core\View;
$money=static fn(mixed $v):string=>'R$ '.number_format((float)$v,2,',','.');
$date=static function(?string $v):string{if(!$v)return '—';$t=strtotime($v);return $t?date('d/m/Y',$t):$v;};
$statusLabel=['active'=>'Ativa','inactive'=>'Inativa','suspended'=>'Suspensa','trialing'=>'Teste','overdue'=>'Em atraso','canceled'=>'Cancelada','open'=>'Aberta','paid'=>'Paga','cancelled'=>'Cancelada','monthly'=>'Mensal','quarterly'=>'Trimestral','semiannual'=>'Semestral','annual'=>'Anual'];
$activeSubscriptions=count(array_filter($tenants,static fn(array $t):bool=>in_array(($t['billing_status']??''),['active','trialing','overdue'],true)));
$mrr=array_sum(array_map(static fn(array $t):float=>in_array(($t['billing_status']??''),['active','trialing','overdue'],true)?(float)($t['amount']??0):0.0,$tenants));
$openInvoices=count(array_filter($invoices,static fn(array $i):bool=>in_array(($i['status']??''),['open','overdue'],true)));
$overdueInvoices=count(array_filter($invoices,static fn(array $i):bool=>($i['status']??'')==='overdue'));
?>
